const fs = require('fs');
const STATE_FILE = '/tmp/aktien_signale_state.json';

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    const https = require('https');
    const req = https.get(url, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
        'Accept': 'application/json',
      }
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { reject(e); } });
    });
    req.on('error', reject);
    req.setTimeout(10000, () => { req.destroy(new Error('timeout')); });
  });
}

// Fetch EUR rates for all relevant currencies
const pairs = ['USDEUR=X','GBPEUR=X','CHFEUR=X','NOKEUR=X','CADEUR=X',
               'AUDEUR=X','JPYEUR=X','HKDEUR=X','KRWEUR=X','SGDEUR=X',
               'DKKEUR=X','PLNEUR=X','CNYEUR=X','ZAREUR=X','BRLEUR=X',
               'ILSEUR=X','SEKEUR=X'];

const rates = { EUR: 1.0 };
for (const pair of pairs) {
  try {
    const data = await httpsGet(`https://query1.finance.yahoo.com/v8/finance/chart/${pair}?interval=1d&range=5d`);
    const result = data?.chart?.result?.[0];
    if (result) {
      const closes = result.indicators.quote[0].close.filter(v => v !== null && v > 0);
      if (closes.length > 0) {
        const currency = pair.replace('EUR=X', '');
        rates[currency] = closes[closes.length - 1];
      }
    }
  } catch(e) {}
  await new Promise(r => setTimeout(r, 300));
}

let state = { results: [], processedCount: 0, fxRates: { EUR: 1.0 }, totalCompanies: 0 };
try { state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) {}
state.fxRates = rates;
fs.writeFileSync(STATE_FILE, JSON.stringify(state));
return $input.all();

const company = $input.first().json;
const fs = require('fs');
const STATE_FILE = '/tmp/aktien_signale_state.json';
let _state = { fxRates: { EUR: 1.0 } };
try { _state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) {}
const fxRates = _state.fxRates || { EUR: 1.0 };

function httpsGet(url) {
  return new Promise((resolve, reject) => {
    const https = require('https');
    const req = https.get(url, {
      headers: {
        'User-Agent': 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/120.0.0.0 Safari/537.36',
        'Accept': 'application/json',
      }
    }, (res) => {
      let data = '';
      res.on('data', chunk => data += chunk);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { reject(e); } });
    });
    req.on('error', reject);
    req.setTimeout(15000, () => { req.destroy(new Error('timeout')); });
  });
}

let ticker = null;
try {
  const searchData = await httpsGet(`https://query2.finance.yahoo.com/v1/finance/search?q=${encodeURIComponent(company.isin)}&lang=en-US&region=US&quotesCount=10&newsCount=0&enableFuzzyQuery=false`);
  const quotes = searchData?.quotes || [];
  if (quotes.length > 0) {
    const muTicker = quotes.find(q => q.quoteType === 'EQUITY' && q.symbol.endsWith('.MU'));
    const tgTicker = quotes.find(q => q.quoteType === 'EQUITY' && q.symbol.endsWith('.TG'));
    const equity = muTicker || tgTicker || quotes.find(q => q.quoteType === 'EQUITY') || quotes[0];
    ticker = equity.symbol;
  }
} catch(e) {
  return [{ json: { skipped: true, reason: 'ticker_search_failed: ' + e.message, company: company.name } }];
}

if (!ticker) {
  return [{ json: { skipped: true, reason: 'no_ticker', company: company.name } }];
}

let ohlc = null;
let currency = 'EUR';
let fxRate = 1.0;
try {
  const chartData = await httpsGet(`https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(ticker)}?interval=1d&range=1y`);
  const result = chartData?.chart?.result?.[0];
  if (result) {
    currency = result.meta?.currency || 'EUR';
    const q = result.indicators.quote[0];

    // Determine EUR conversion factor
    fxRate = 1.0;
    if (currency === 'GBp' || currency === 'GBX') {
      // British pence: divide by 100 then GBP→EUR
      fxRate = (fxRates['GBP'] || 1.0) / 100;
    } else if (currency !== 'EUR') {
      fxRate = fxRates[currency] || 1.0;
    }

    ohlc = {
      open:  q.open,
      high:  q.high,
      low:   q.low,
      close: q.close,
    };
  }
} catch(e) {
  return [{ json: { skipped: true, reason: 'chart_fetch_failed: ' + e.message, company: company.name, ticker } }];
}

if (!ohlc) {
  return [{ json: { skipped: true, reason: 'no_ohlc', company: company.name, ticker } }];
}

return [{ json: { ...company, ticker, currency, fxRate, ohlc } }];

const data = $input.first().json;
const fs = require('fs');
const STATE_FILE = '/tmp/aktien_signale_state.json';
const PERSISTENT_FILE = '/home/node/.n8n/aktien_signale_persistent.json';
let sd = { results: [], processedCount: 0, fxRates: { EUR: 1.0 }, totalCompanies: 0 };
try { sd = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) {}
let persistent = { sentToday: null, positions: {} };
try { persistent = JSON.parse(fs.readFileSync(PERSISTENT_FILE, 'utf8')); } catch(e) {}
if (!persistent.positions) persistent.positions = {};
const fxRate = data.fxRate || 1.0;
if (!sd.results) sd.results = [];
sd.processedCount = (sd.processedCount || 0) + 1;

if (data.skipped || !data.ohlc) {
  return [{ json: { processed: false, company: data.name || 'unknown', processedCount: sd.processedCount, totalCompanies: sd.totalCompanies || 0 } }];
}

const { high: hi, low: lo, close: cl } = data.ohlc;

let n = cl.length;
while (n > 0 && (cl[n-1] === null || cl[n-1] === undefined || isNaN(cl[n-1]))) n--;
if (n < 60) {
  return [{ json: { processed: false, reason: 'insufficient_data', company: data.name, processedCount: sd.processedCount, totalCompanies: sd.totalCompanies || 0 } }];
}

const c = cl.slice(0, n);
const h = hi.slice(0, n);
const l = lo.slice(0, n);

// === Parameter (identisch zu tradingview-ai-strategy-2) ===
const fastLen=9, slowLen=21, rsiLen=14, stochLen=14, stochSmooth=3;
const stochOS=20, macdFast=12, macdSlow=26, macdSig=9;
const bbLen=20, bbMult=2.0, wrLen=14, wrOS=-80, minScore=4;
const atrLen=14, trailMult=2.0, minProfitPct=5.0, trailActivatePct=8.0;

function ema(arr, period) {
  const k = 2/(period+1), res = [];
  res[0] = arr[0] ?? 0;
  for (let i=1;i<arr.length;i++) res[i] = (arr[i] ?? res[i-1]) * k + res[i-1] * (1-k);
  return res;
}
function sma(arr, period) {
  const res = new Array(arr.length).fill(null);
  for (let i=period-1;i<arr.length;i++) {
    let sum=0,cnt=0;
    for(let j=i-period+1;j<=i;j++) if(arr[j]!==null){sum+=arr[j];cnt++;}
    if(cnt===period) res[i]=sum/period;
  }
  return res;
}
function stdev(arr, period) {
  const res = new Array(arr.length).fill(null);
  for(let i=period-1;i<arr.length;i++) {
    let sum=0,cnt=0;
    for(let j=i-period+1;j<=i;j++) if(arr[j]!==null){sum+=arr[j];cnt++;}
    if(cnt<period) continue;
    const mean=sum/cnt; let v=0;
    for(let j=i-period+1;j<=i;j++) v+=(arr[j]-mean)**2;
    res[i]=Math.sqrt(v/cnt);
  }
  return res;
}
function calcRSI(arr, period) {
  const res=new Array(arr.length).fill(null);
  let ag=0,al=0;
  for(let i=1;i<=period;i++){const d=arr[i]-arr[i-1];d>0?ag+=d:al-=d;}
  ag/=period;al/=period;
  res[period]=al===0?100:100-100/(1+ag/al);
  for(let i=period+1;i<arr.length;i++){
    const d=arr[i]-arr[i-1],g=d>0?d:0,ls=d<0?-d:0;
    ag=(ag*(period-1)+g)/period;al=(al*(period-1)+ls)/period;
    res[i]=al===0?100:100-100/(1+ag/al);
  }
  return res;
}
// Wilder's RMA (wie TradingView ta.atr)
function rma(arr, period) {
  const res = new Array(arr.length).fill(null);
  let seed = 0, cnt = 0, startIdx = -1;
  for(let i=0;i<arr.length;i++) {
    if(arr[i]===null||isNaN(arr[i])) continue;
    if(cnt < period) { seed += arr[i]; cnt++; if(cnt===period){ res[i]=seed/period; startIdx=i; } }
    else { res[i] = arr[i]/period + res[i-1]*(1-1/period); }
  }
  return res;
}
function calcATR(h, l, c, period) {
  const tr = new Array(c.length).fill(null);
  for(let i=1;i<c.length;i++) {
    if(c[i]===null||c[i-1]===null||h[i]===null||l[i]===null) continue;
    tr[i] = Math.max(h[i]-l[i], Math.abs(h[i]-c[i-1]), Math.abs(l[i]-c[i-1]));
  }
  return rma(tr, period);
}

const fastEMA = ema(c, fastLen);
const slowEMA = ema(c, slowLen);
const rsiArr  = calcRSI(c, rsiLen);

const stochRaw = new Array(n).fill(null);
for(let i=stochLen-1;i<n;i++){
  const sl=rsiArr.slice(i-stochLen+1,i+1).filter(v=>v!==null);
  if(sl.length<stochLen) continue;
  const mn=Math.min(...sl),mx=Math.max(...sl);
  stochRaw[i]=mx-mn===0?0:(rsiArr[i]-mn)/(mx-mn)*100;
}
const stochK = sma(stochRaw, stochSmooth);

const emaF = ema(c, macdFast), emaS = ema(c, macdSlow);
const macdLine = emaF.map((v,i)=>v-emaS[i]);
const sigLine  = ema(macdLine, macdSig);

const bbMidArr = sma(c, bbLen);
const bbStdev  = stdev(c, bbLen);
const bbLower  = bbMidArr.map((v,i)=>v!==null&&bbStdev[i]!==null?v-bbMult*bbStdev[i]:null);

const wrArr = new Array(n).fill(null);
for(let i=wrLen-1;i<n;i++){
  const mxH=Math.max(...h.slice(i-wrLen+1,i+1));
  const mnL=Math.min(...l.slice(i-wrLen+1,i+1));
  wrArr[i]=mxH-mnL===0?-100:(mxH-c[i])/(mxH-mnL)*-100;
}

const atrArr = calcATR(h, l, c, atrLen);

const i=n-1, p=n-2;

// Buy-Signale
const sigEmaBuy   = fastEMA[p]<slowEMA[p] && fastEMA[i]>=slowEMA[i] ? 1 : 0;
const sigStochBuy = stochK[p]!==null&&stochK[i]!==null&&stochK[p]<stochOS&&stochK[i]>=stochOS ? 1 : 0;
const sigMacdBuy  = macdLine[p]<sigLine[p] && macdLine[i]>=sigLine[i] ? 1 : 0;
const sigBbBuy    = bbLower[p]!==null&&c[p]<bbLower[p]&&c[i]>=bbLower[i] ? 1 : 0;
const sigWrBuy    = wrArr[p]!==null&&wrArr[i]!==null&&wrArr[p]<wrOS&&wrArr[i]>=wrOS ? 1 : 0;
const buyScore    = sigEmaBuy+sigStochBuy+sigMacdBuy+sigBbBuy+sigWrBuy;

// Sell-Signale
const sigEmaSell   = fastEMA[p]>slowEMA[p] && fastEMA[i]<=slowEMA[i] ? 1 : 0;
const sigMacdSell  = macdLine[p]>sigLine[p] && macdLine[i]<=sigLine[i] ? 1 : 0;
const sigStochSell = stochK[i]!==null&&stochK[p]!==null&&stochK[i]<stochK[p]&&stochK[i]>80 ? 1 : 0;
const sigWrSell    = wrArr[i]!==null&&wrArr[i]>-20 ? 1 : 0;
const sellScore    = sigEmaSell+sigMacdSell+sigStochSell+sigWrSell;

const hasBuy  = buyScore >= minScore;
const hasSell = sigEmaSell === 1 && (sellScore - sigEmaSell) >= 1;

const alreadySent = (persistent.sentToday?.stocks || []).includes(data.name);
const pos = persistent.positions[data.name] || null;
const inPosition = !!pos;

// === Trailing Stop aktualisieren (für offene Positionen) ===
let trailHit = false;
if (inPosition) {
  // bestHigh mit aktuellem High nachziehen
  if (!pos.bestHigh || h[i] > pos.bestHigh) pos.bestHigh = h[i];

  const trailActivated = pos.bestHigh >= pos.entryPrice * (1 + trailActivatePct / 100);
  if (trailActivated) {
    const minExit = pos.entryPrice * (1 + minProfitPct / 100);
    const newTrail = Math.max(pos.bestHigh - (pos.entryAtr || atrArr[i] || 0) * trailMult, minExit);
    pos.trailSl = pos.trailSl ? Math.max(pos.trailSl, newTrail) : newTrail;
  }

  const trailActive = pos.trailSl && pos.trailSl > pos.entryPrice;
  trailHit = trailActive && c[i] <= pos.trailSl;
}

const detailsBuy  = [sigEmaBuy?'EMA':'',sigStochBuy?'StochRSI':'',sigMacdBuy?'MACD':'',sigBbBuy?'BB':'',sigWrBuy?'W%R':''].filter(Boolean).join('+');
const detailsSell = [sigEmaSell?'EMA':'',sigMacdSell?'MACD':'',sigStochSell?'StochRSI':'',sigWrSell?'W%R':''].filter(Boolean).join('+');

// === VERKAUF: Trail-SL ODER Sell-Signal mit Mindestgewinn (+5%) ===
if (!alreadySent && inPosition) {
  const inProfit = c[i] >= pos.entryPrice * (1 + minProfitPct / 100);
  const sellSignal = inProfit && hasSell;
  const reason = trailHit ? 'Trail-SL' : `Sell-Signal(${sellScore}/4)`;

  if (trailHit || sellSignal) {
    const pct = ((c[i] - pos.entryPrice) / pos.entryPrice * 100).toFixed(2);
    delete persistent.positions[data.name];
    sd.results.push({
      name:    data.name,
      branche: data.branche,
      isin:    data.isin,
      ticker:  data.ticker,
      signal:  'VERKAUF',
      score:   `${sellScore}/4`,
      preis:   (c[i] * fxRate).toFixed(2),
      pct:     `+${pct}%`,
      details: reason,
    });
  }
}

// === KAUF: kein Trailing Stop, keine offene Position ===
if (!alreadySent && hasBuy && !inPosition) {
  persistent.positions[data.name] = {
    entryDate:  new Date().toISOString().slice(0,10),
    entryPrice: c[i],
    entryAtr:   atrArr[i] || 0,
    bestHigh:   h[i],
    trailSl:    null,
  };
  sd.results.push({
    name:    data.name,
    branche: data.branche,
    isin:    data.isin,
    ticker:  data.ticker,
    signal:  'KAUF',
    score:   `${buyScore}/5`,
    preis:   (c[i] * fxRate).toFixed(2),
    details: detailsBuy,
  });
}

fs.writeFileSync(STATE_FILE, JSON.stringify(sd));
fs.writeFileSync(PERSISTENT_FILE, JSON.stringify(persistent));
return [{ json: { processed: true, company: data.name, ticker: data.ticker, buyScore, sellScore, hasBuy, hasSell, trailHit, processedCount: sd.processedCount, totalCompanies: sd.totalCompanies || 0 } }];

const fs = require('fs');
const STATE_FILE = '/tmp/aktien_signale_state.json';
let sd = { results: [] };
try { sd = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) {}
const results = sd.results || [];

if (results.length === 0) {
  return [{ json: { count: 0, text: '', hasSignals: false } }];
}

const now   = new Date();
const today = now.toLocaleDateString('de-DE', { day: '2-digit', month: '2-digit', year: 'numeric' });
const time  = now.toLocaleTimeString('de-DE', { hour: '2-digit', minute: '2-digit' });

// WKN aus DE-ISIN ableiten (Positionen 4-9)
function getWKN(isin) {
  if (isin && isin.startsWith('DE')) return isin.slice(4, 10);
  return null;
}

const kaufSignale    = results.filter(r => r.signal === 'KAUF');
const verkaufSignale = results.filter(r => r.signal === 'VERKAUF');

let text = `<b>📊 Strategie-Signale ${today} um ${time} Uhr</b>\n`;
text += `<i>(Aktien Aktiv v5 – EMA/StochRSI/MACD/BB/W%R, Preise in EUR)</i>\n`;

function formatEntry(r) {
  const wkn = getWKN(r.isin);
  const ids  = wkn
    ? `WKN: <code>${wkn}</code> | ISIN: <code>${r.isin}</code>`
    : `ISIN: <code>${r.isin}</code>`;
  return `• <b>${r.name}</b> (${r.ticker}) – Score: ${r.score}\n`
       + `  ${r.branche} | Kurs: ${r.preis} €\n`
       + `  ${ids}\n`
       + `  Indikatoren: ${r.details}\n`;
}

if (kaufSignale.length > 0) {
  text += `\n<b>🟢 KAUF-Signale (${kaufSignale.length})</b>\n`;
  for (const r of kaufSignale)    text += formatEntry(r);
}
if (verkaufSignale.length > 0) {
  text += `\n<b>🔴 VERKAUF-Signale (${verkaufSignale.length})</b>\n`;
  for (const r of verkaufSignale) text += formatEntry(r);
}

return [{ json: { count: results.length, text, hasSignals: true } }];

const fs = require('fs');
const STATE_FILE = '/tmp/aktien_signale_state.json';
const PERSISTENT_FILE = '/home/node/.n8n/aktien_signale_persistent.json';
let state = { results: [] };
try { state = JSON.parse(fs.readFileSync(STATE_FILE, 'utf8')); } catch(e) {}
let persistent = { sentToday: null, positions: {} };
try { persistent = JSON.parse(fs.readFileSync(PERSISTENT_FILE, 'utf8')); } catch(e) {}
const results = state.results || [];
const todayDate = new Date().toISOString().slice(0, 10);

if (!persistent.sentToday || persistent.sentToday.date !== todayDate) {
  persistent.sentToday = { date: todayDate, stocks: [] };
}

for (const r of results) {
  if (!persistent.sentToday.stocks.includes(r.name)) {
    persistent.sentToday.stocks.push(r.name);
  }
}

fs.writeFileSync(PERSISTENT_FILE, JSON.stringify(persistent));
return $input.all();
